import os
def env_or(key, default):
    return os.environ.get(key, default)
print(env_or("NOEXISTE_PYARCANA", "def"))

def merge_cfg(*layers):
    out = {}
    for layer in layers:
        if layer:
            out.update(layer)
    return out
print(merge_cfg({"x":1}, {"x":2, "y":3}))

def exit_usage():
    raise SystemExit(2)
try:
    exit_usage()
except SystemExit as e:
    print("code", e.code)

def run(ok):
    return 0 if ok else 1
print(run(True), run(False))

def bump(ver, kind):
    maj, mi, pa = map(int, ver.split("."))
    if kind == "major":
        return f"{maj+1}.0.0"
    if kind == "minor":
        return f"{maj}.{mi+1}.0"
    return f"{maj}.{mi}.{pa+1}"
print(bump("0.1.0", "minor"), bump("0.1.0", "patch"))

def subcommands():
    return {"ingest": "run ingest", "validate": "run validate"}
print(sorted(subcommands()))

def dispatch(cmd, registry):
    if cmd not in registry:
        raise SystemExit(2)
    return registry[cmd]
print(dispatch("ingest", {"ingest": "ok"}))

def smoke_cli():
    return {"exit": 0, "stdout": "{\"ok\": true}"}
print(smoke_cli())

def public_api():
    return ["main", "load_config", "dispatch"]
print(public_api())
